## Context

Text operations are critical for editor applications. The rope-based TextBuffer and EditBuffer need to perform well for:
- Large documents (10K+ lines)
- Frequent insertions (typing)
- Cursor movement
- Undo/redo operations

## Benchmarks to Add

### Rope Basic Operations
```rust
fn bench_rope_insert(c: &mut Criterion) {
    let mut group = c.benchmark_group("rope_insert");

    // Insert at beginning
    group.bench_function("insert_beginning", |b| {
        let mut buffer = TextBuffer::with_text(&"x".repeat(10000));
        b.iter(|| {
            buffer.insert(0, "abc");
        })
    });

    // Insert at middle
    group.bench_function("insert_middle", |b| {
        let mut buffer = TextBuffer::with_text(&"x".repeat(10000));
        b.iter(|| {
            buffer.insert(5000, "abc");
        })
    });

    // Insert at end
    group.bench_function("insert_end", |b| {
        let mut buffer = TextBuffer::with_text(&"x".repeat(10000));
        b.iter(|| {
            buffer.insert(10000, "abc");
        })
    });

    group.finish();
}

fn bench_rope_delete(c: &mut Criterion) {
    let mut group = c.benchmark_group("rope_delete");

    group.bench_function("delete_beginning_10", |b| {
        let text = "x".repeat(10000);
        b.iter_batched(
            || TextBuffer::with_text(&text),
            |mut buffer| buffer.delete(0..10),
            BatchSize::SmallInput,
        )
    });

    group.bench_function("delete_middle_10", |b| {
        let text = "x".repeat(10000);
        b.iter_batched(
            || TextBuffer::with_text(&text),
            |mut buffer| buffer.delete(5000..5010),
            BatchSize::SmallInput,
        )
    });

    group.finish();
}
```

### Line Operations
```rust
fn bench_line_iteration(c: &mut Criterion) {
    let text = (0..1000).map(|i| format!("Line {i}\n")).collect::<String>();
    let buffer = TextBuffer::with_text(&text);

    c.bench_function("iterate_1000_lines", |b| {
        b.iter(|| {
            for line in buffer.lines() {
                black_box(line);
            }
        })
    });
}

fn bench_line_access(c: &mut Criterion) {
    let text = (0..1000).map(|i| format!("Line {i}\n")).collect::<String>();
    let buffer = TextBuffer::with_text(&text);

    c.bench_function("random_line_access_100", |b| {
        b.iter(|| {
            for i in [0, 500, 999, 250, 750, 100, 900, 50, 950, 333] {
                black_box(buffer.line(i));
            }
        })
    });
}
```

### EditBuffer Operations
```rust
fn bench_editbuffer_typing(c: &mut Criterion) {
    // Simulate typing a sentence
    let sentence = "The quick brown fox jumps over the lazy dog. ";

    c.bench_function("type_sentence", |b| {
        b.iter_batched(
            || EditBuffer::new(),
            |mut eb| {
                for ch in sentence.chars() {
                    eb.insert(&ch.to_string());
                }
            },
            BatchSize::SmallInput,
        )
    });
}

fn bench_editbuffer_undo_redo(c: &mut Criterion) {
    let mut group = c.benchmark_group("undo_redo");

    group.bench_function("undo_10_operations", |b| {
        b.iter_batched(
            || {
                let mut eb = EditBuffer::new();
                for i in 0..10 {
                    eb.insert(&format!("text{i}"));
                    eb.commit();
                }
                eb
            },
            |mut eb| {
                for _ in 0..10 {
                    eb.undo();
                }
            },
            BatchSize::SmallInput,
        )
    });

    group.bench_function("redo_10_operations", |b| {
        b.iter_batched(
            || {
                let mut eb = EditBuffer::new();
                for i in 0..10 {
                    eb.insert(&format!("text{i}"));
                    eb.commit();
                }
                for _ in 0..10 {
                    eb.undo();
                }
                eb
            },
            |mut eb| {
                for _ in 0..10 {
                    eb.redo();
                }
            },
            BatchSize::SmallInput,
        )
    });

    group.finish();
}
```

### Cursor Movement
```rust
fn bench_cursor_movement(c: &mut Criterion) {
    let text = (0..100).map(|i| format!("Line {i} with some content\n")).collect::<String>();
    let mut eb = EditBuffer::with_text(&text);

    let mut group = c.benchmark_group("cursor_movement");

    group.bench_function("move_right_1000", |b| {
